#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id (POD type)
        stream << packet_id;

        // Write username with length prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count + scores using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer_adaptor for std::vector<uint8_t>
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream from the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Use the stream's serialise method to serialize the packet
    stream.serialise(packet);

    // Return the serialized buffer
    return buffer;
}
```

## Key Implementation Points:

1. **`serialise` method implementation**:
   - Uses `stream << packet_id` for POD type serialization
   - Uses `hexi::prefixed(username)` for username with length prefix
   - Uses `hexi::prefixed(scores)` for scores count + elements
   - Uses `hexi::null_terminated(metadata)` for null-terminated string

2. **`serialize_packet` function**:
   - Creates `buffer_adaptor` for `std::vector<uint8_t>`
   - Creates `binary_stream` from the adaptor
   - Calls `stream.serialise(packet)` to perform serialization
   - Returns the populated buffer

3. **Proper use of Hexi library components**:
   - Correctly uses `prefixed` and `null_terminated` adaptors
   - Follows the serialization pattern shown in the reference materials
   - Maintains proper object lifetimes and dependencies

