struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object using the input buffer
    hexi::deserializer<std::vector<uint8_t>> deserializer(buffer);

    NetworkPacket packet;

    // Read packet_id using operator>>
    deserializer >> packet.packet_id;

    // Read username using prefixed adaptor
    deserializer >> hexi::prefixed(packet.username);

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    deserializer >> score_count;
    hexi::read_container(deserializer, packet.scores, score_count);

    // Read metadata string as null_terminated
    deserializer >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    auto bytes_read = deserializer.total_read();
    auto remaining_bytes = buffer.size() - bytes_read;
    if (remaining_bytes > 0) {
        deserializer.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object using the input buffer
    hexi::deserializer<std::vector<uint8_t>> deserializer(buffer);

    PacketInfo info;

    // Use span() to get a zero-copy view of packet_id
    auto packet_id_span = deserializer.span<uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Read username using prefixed adaptor to get string_view
