```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

std::vector<uint32_t> read_item_batch(const std::span<const uint8_t> buffer) {
    // Create a binary_stream object from the buffer
    hexi::binary_stream stream(buffer);

    // Read the item_count using hexi::endian::le adaptor
    uint32_t item_count;
    stream >> hexi::endian::le(item_count);

    // Create a vector to store the items
    std::vector<uint32_t> items;

    // Use read_container to read all items into the vector
    hexi::pmc::read_container(items, item_count);

    return items;
}
```

