This implementation clearly demonstrates how the block allocator manages its internal free list using the `push()` and `pop()` methods through observable allocation/deallocation patterns.

output.result:
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with 64-byte blocks and specified element count
    hexi::block_allocator<64, element_count> allocator;

    std::cout << "=== Block Allocator Demonstration ===" << std::endl;
    std::cout << "Block size: 64 bytes, Elements: " << element_count << std::endl;
    std::cout << "\nInitial state: Free list contains " << element_count 
              << " pre-allocated blocks" << std::endl;

    // Demonstrate allocation - uses pop() internally
    std::vector<void*> allocated_blocks;
    for (size_t i = 0; i < element_count; ++i) {
        void* block = allocator.allocate();
        allocated_blocks.push_back(block);
        std::cout << "Allocated block " << i+1 << " (total: " << i+1 
                  << " allocated, " << element_count - (i+1) 
                  << " remaining in free list)" << std::endl;
    }

    // Demonstrate deallocation - uses push() internally
    std::cout << "\nDeallocating blocks in reverse order to show LIFO behavior:" << std::endl;
    for (auto it = allocated_blocks.rbegin(); it != allocated_blocks.rend(); ++it) {
        allocator.deallocate(*it);
        std::cout << "Deallocated block" << std::endl;
    }

    // Demonstrate reallocation - shows that deallocated blocks are reused
    std::cout << "\nRe-allocating blocks after full deallocation:" << std::endl;
    allocated_blocks.clear();
    for (size_t i = 0; i < element_count; ++i) {
        void* block = allocator.allocate();
        allocated_blocks.push_back(block);
        std::cout << "Re-allocated block " << i+1 << " (using previously deallocated space)" << std::endl;
    }

    // Clean up remaining allocations
    for (auto block : allocated_blocks) {
        allocator.deallocate(block);
    }

    std::cout << "\n=== Demonstration Complete ===" << std::endl;
}

// Example usage
int main() {
    demonstrate_block_allocator_behavior<5>(); // Use 5 elements for demonstration
    return 0;
}

