std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create a buffer_write_adaptor instance using the buffer
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Iterate through each chunk in the input vector
    for (const auto& chunk : chunks) {
        // Check if there's enough free space using free()
        if (adaptor.free() < chunk.size()) {
            // If not enough space, resize the buffer appropriately
            buffer.resize(buffer.size() + chunk.size());
        }

        // Write the chunk using write()
        adaptor.write(chunk.data(), chunk.size());
    }

    // After processing all chunks, return the total size written using size()
    return adaptor.size();
}

