    // Create a binary stream for reading
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Extract message_id using span for zero-copy view
    auto id_span = stream.span<uint32_t>(1);
    header.message_id = hexi::endian::big_to_native(id_span[0]);

    // Skip past the header (4 bytes)
    stream.skip(4);

    return header;
}

