Based on the reference materials and detailed specifications, here's the complete implementation for the exam question:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert from native to little-endian
        adaptor.write(sensor_id);

        for (auto temp : temperatures) {
            float converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        double converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Deserialization: convert from little-endian to native
        adaptor.read(&sensor_id);

        for (auto& temp : temperatures) {
            float temp_value;
            adaptor.read(&temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            temp = temp_value;
        }

        double pressure_value;
        adaptor.read(&pressure_value);
        hexi::endian::little_to_native_inplace(pressure_value);
        pressure = pressure_value;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Extract sensor name using view (null-terminated string)
    std::string_view sensor_name = stream.view();

    // Check bounds for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    uint32_t sensor_id;
    stream.read(&sensor_id);

    // Skip remaining data
    stream.skip(stream.size() - stream.total_read());

    return {sensor_id, sensor_name};
}
```

